+package config
+
+import (
+	"encoding/json"
+	"os"
+	"path/filepath"
+	"sync"
+)
+
+const reloadStatusFilename = "reload-status.json"
+
+// ReloadStatus describes the outcome of the most recent transactional
+// configuration reload.
+type ReloadStatus struct {
+	LastReloadID         string           `json:"last_reload_id"`
+	LastReloadSuccessful bool             `json:"last_reload_successful"`
+	ErrorCategory        string           `json:"error_category"`
+	ErrorMessage         string           `json:"error_message"`
+	AppliedReloaders     []string         `json:"applied_reloaders"`
+	RollbackAttempted    bool             `json:"rollback_attempted"`
+	RollbackSuccessful   bool             `json:"rollback_successful"`
+	FailedReloader       string           `json:"failed_reloader"`
+	ReloaderTimingsMS    map[string]int64 `json:"reloader_timings_ms"`
+}
+
+// DefaultReloadStatus is returned until the first reload attempt.
+func DefaultReloadStatus() ReloadStatus {
+	return ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+// ReloadStatusStore keeps reload status available concurrently and persists it
+// best-effort. A malformed or unavailable state file deliberately behaves as
+// an empty status.
+type ReloadStatusStore struct {
+	mu     sync.RWMutex
+	path   string
+	status ReloadStatus
+}
+
+func NewReloadStatusStore(storageDir string) *ReloadStatusStore {
+	s := &ReloadStatusStore{path: filepath.Join(storageDir, reloadStatusFilename), status: DefaultReloadStatus()}
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		return s
+	}
+	var status ReloadStatus
+	if json.Unmarshal(b, &status) != nil || !validReloadStatus(status) {
+		return s
+	}
+	s.status = normalizeReloadStatus(status)
+	return s
+}
+
+func validReloadStatus(s ReloadStatus) bool {
+	switch s.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+func normalizeReloadStatus(s ReloadStatus) ReloadStatus {
+	if s.AppliedReloaders == nil {
+		s.AppliedReloaders = []string{}
+	}
+	if s.ReloaderTimingsMS == nil {
+		s.ReloaderTimingsMS = map[string]int64{}
+	}
+	return s
+}
+
+func (s *ReloadStatusStore) Get() ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	status := normalizeReloadStatus(s.status)
+	status.AppliedReloaders = append([]string(nil), status.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]int64, len(s.status.ReloaderTimingsMS))
+	for k, v := range s.status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[k] = v
+	}
+	return status
+}
+
+// Set records the supplied status. Persistence errors do not interfere with a
+// reload; the in-memory value remains available through the status API.
+func (s *ReloadStatusStore) Set(status ReloadStatus) {
+	status = normalizeReloadStatus(status)
+	s.mu.Lock()
+	s.status = status
+	s.mu.Unlock()
+
+	b, err := json.Marshal(status)
+	if err != nil {
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(s.path), 0o755); err != nil {
+		return
+	}
+	tmp, err := os.CreateTemp(filepath.Dir(s.path), ".reload-status-*")
+	if err != nil {
+		return
+	}
+	tmpName := tmp.Name()
+	defer os.Remove(tmpName)
+	if _, err := tmp.Write(b); err != nil {
+		tmp.Close()
+		return
+	}
+	if err := tmp.Chmod(0o644); err != nil {
+		tmp.Close()
+		return
+	}
+	if err := tmp.Close(); err != nil {
+		return
+	}
+	_ = os.Rename(tmpName, s.path)
+}
