+func (t *transactionalConfigReloader) apply(conf *config.Config, filename string, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, recordOutcome bool, rls []reloader) error {
+	start := time.Now()
+	outcome := config.ReloadStatus{
+		LastReloadID:      start.UTC().Format(time.RFC3339Nano),
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	}
+
+	for i, rl := range rls {
+		rstart := time.Now()
+		err := rl.reloader(conf)
+		outcome.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(rstart))
+		if err == nil {
+			outcome.AppliedReloaders = append(outcome.AppliedReloaders, rl.name)
+			continue
+		}
+
+		logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
+		outcome.ErrorCategory = "apply_error"
+		outcome.ErrorMessage = err.Error()
+		outcome.FailedReloader = rl.name
+		if i > 0 && t.lastKnownGood != nil {
+			outcome.RollbackAttempted = true
+			outcome.RollbackSuccessful = true
+			for j := i - 1; j >= 0; j-- {
+				if rollbackErr := rls[j].reloader(t.lastKnownGood); rollbackErr != nil {
+					logger.Error("Failed to roll back configuration", "reloader", rls[j].name, "err", rollbackErr)
+					outcome.ErrorCategory = "rollback_error"
+					outcome.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed in %s: %v", rl.name, err, rls[j].name, rollbackErr)
+					outcome.FailedReloader = rls[j].name
+					outcome.RollbackSuccessful = false
+					break
+				}
+			}
+		}
+		if recordOutcome {
+			t.status.Set(outcome)
+		}
+		return fmt.Errorf("error applying configuration with reloader %q (--config.file=%q): %w", rl.name, filename, err)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	t.lastKnownGood = conf
+	outcome.LastReloadSuccessful = true
+	if recordOutcome {
+		t.status.Set(outcome)
+	}
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
