+}
+
+// DefaultReloadStatus is returned until the first reload attempt.
+func DefaultReloadStatus() ReloadStatus {
+	return ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+// ReloadStatusStore keeps reload status available concurrently and persists it
+// best-effort. A malformed or unavailable state file deliberately behaves as
+// an empty status.
+type ReloadStatusStore struct {
+	mu     sync.RWMutex
+	path   string
+	status ReloadStatus
+}
+
+func NewReloadStatusStore(storageDir string) *ReloadStatusStore {
+	s := &ReloadStatusStore{path: filepath.Join(storageDir, reloadStatusFilename), status: DefaultReloadStatus()}
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		return s
+	}
+	var status ReloadStatus
+	if json.Unmarshal(b, &status) != nil || !validReloadStatus(status) {
+		return s
+	}
+	s.status = normalizeReloadStatus(status)
+	return s
+}
+
+func validReloadStatus(s ReloadStatus) bool {
+	switch s.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+func normalizeReloadStatus(s ReloadStatus) ReloadStatus {
+	if s.AppliedReloaders == nil {
